/**
 * Sliding window rate limiting middleware for Express.
 *
 * TRUE sliding window: every request's timestamp is stored, and on each incoming
 * request we discard timestamps older than `windowMs` relative to *now*. The limit
 * is enforced against the count of timestamps still inside that moving window.
 * There is no fixed bucket that resets on a clock boundary, so a client cannot
 * burst 2x the limit across a reset edge (the classic fixed-window flaw).
 *
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000]      Window size in milliseconds.
 * @param {number} [options.maxRequests=100]     Max requests allowed per window.
 * @param {(req)=>string} [options.keyGenerator] Derive the client key (default req.ip).
 * @returns {Function & { close: () => void }} Express middleware with a close() method.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;
  const keyGenerator = options.keyGenerator ?? ((req) => req.ip);

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> -> ascending-sorted list of request timestamps (ms).
  const hits = new Map();

  /**
   * Drop timestamps older than windowStart. Because timestamps are appended in
   * chronological order, all expired entries sit at the front of the array, so we
   * slice from the first surviving index. Returns the same array if nothing expired.
   */
  function prune(timestamps, windowStart) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= windowStart) i++;
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    // Pull the client's history and drop anything that has slid out of the window.
    let timestamps = prune(hits.get(key) || [], windowStart);

    if (timestamps.length >= maxRequests) {
      // Over the limit. The window frees a slot when the OLDEST in-window request
      // ages out, i.e. oldest + windowMs.
      hits.set(key, timestamps); // persist the pruned list
      const resetMs = timestamps[0] + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('Retry-After', retryAfterSec);
      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // Under the limit: record this request and allow it through.
    timestamps.push(now);
    hits.set(key, timestamps);

    const remaining = maxRequests - timestamps.length;
    const resetMs = timestamps[0] + windowMs; // when the window fully clears

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    return next();
  };

  // --- Memory management -----------------------------------------------------
  // Every 60s, evict clients that have gone quiet so the Map doesn't grow
  // unbounded with one-off IPs.
  const CLEANUP_INTERVAL_MS = 60000;
  const cleanupTimer = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const pruned = prune(timestamps, windowStart);
      if (pruned.length === 0) hits.delete(key);
      else if (pruned !== timestamps) hits.set(key, pruned);
    }
  }, CLEANUP_INTERVAL_MS);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') cleanupTimer.unref();

  // Explicit teardown so the timer never blocks a graceful shutdown (and so tests
  // can stop it deterministically).
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

