/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * Uses a TRUE sliding window: each client IP maintains a log of request
 * timestamps. On every request the window is recalculated relative to *now*,
 * so there is no fixed-interval "cliff" where a client can burst at a boundary.
 *
 * ─── Proxy / req.ip note ────────────────────────────────────────────────────
 * req.ip is the raw socket address by default.  Behind a reverse proxy (Nginx,
 * AWS ALB, Cloudflare…) every client will share the proxy's IP, making rate-
 * limiting useless.  Fix it once in your app entry point:
 *
 *   app.set('trust proxy', 1);   // trust one hop (adjust to your topology)
 *
 * Express then reads the real client IP from X-Forwarded-For.
 * See: https://expressjs.com/en/guide/behind-proxies.html
 * ────────────────────────────────────────────────────────────────────────────
 */

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window size in milliseconds.
 * @property {number} [maxRequests=100]  - Max requests allowed per window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {import('express').RequestHandler} middleware
 * @property {() => void}                        close      - Clears the cleanup timer.
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param   {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000;  // default: 1 min
  const maxRequests = options.maxRequests ?? 100;     // default: 100 req/window

  if (windowMs    <= 0) throw new RangeError('windowMs must be a positive number');
  if (maxRequests <= 0) throw new RangeError('maxRequests must be a positive number');

  /**
   * Per-IP timestamp log.
   *   Key  : client IP string
   *   Value: ascending array of request timestamps (epoch ms)
   *
   * A plain Map gives O(1) lookup and easy full iteration for cleanup.
   */
  const store = new Map(); // Map<string, number[]>

  // ── Background cleanup ──────────────────────────────────────────────────────
  // Runs every 60 s. Removes IPs whose entire log has expired, so the Map
  // doesn't grow without bound on servers with many distinct clients.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      const active = pruneWindow(timestamps, cutoff);
      if (active.length === 0) {
        store.delete(ip);
      } else {
        store.set(ip, active);
      }
    }
  }, 60_000);

  // Prevent the timer from keeping the process alive (important in tests /
  // worker threads that expect a clean exit).
  if (typeof cleanupInterval.unref === 'function') cleanupInterval.unref();

  // ── Helpers ─────────────────────────────────────────────────────────────────

  /**
   * Returns only timestamps that fall strictly inside the current window.
   * Timestamps are stored ascending, so a binary search finds the cutoff in
   * O(log n) and a single slice copies the live portion in O(k).
   *
   * @param {number[]} timestamps - Ascending epoch-ms array.
   * @param {number}   cutoff     - Oldest timestamp still within the window.
   * @returns {number[]}
   */
  function pruneWindow(timestamps, cutoff) {
    let lo = 0, hi = timestamps.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      timestamps[mid] <= cutoff ? (lo = mid + 1) : (hi = mid);
    }
    // lo === 0 means nothing is stale; skip the slice allocation entirely.
    return lo === 0 ? timestamps : timestamps.slice(lo);
  }

  // ── Middleware ───────────────────────────────────────────────────────────────

  function middleware(req, res, next) {
    const ip          = req.ip || req.socket?.remoteAddress || 'unknown';
    const now         = Date.now();
    const windowStart = now - windowMs;

    // Retrieve and prune the log for this IP.
    const raw    = store.get(ip) ?? [];
    const active = pruneWindow(raw, windowStart);
    const count  = active.length;  // requests already in the current window

    // ── Rejected ──────────────────────────────────────────────────────────────
    if (count >= maxRequests) {
      // The oldest timestamp still in the window tells us the exact moment a
      // slot opens up — no rounding up to a fixed reset period.
      const oldestInWindow = active[0];                // active.length >= maxRequests > 0
      const resetMs        = oldestInWindow + windowMs;
      const retryAfterSec  = Math.ceil((resetMs - now) / 1000);

      res.set('Retry-After', String(retryAfterSec));

      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // ── Allowed ───────────────────────────────────────────────────────────────
    active.push(now);         // append; array stays sorted — now is always newest
    store.set(ip, active);

    const remaining = maxRequests - active.length;

    // X-RateLimit-Reset = epoch *seconds* when the oldest recorded timestamp
    // expires (i.e. the window leading edge as it slides forward).
    const resetEpoch = Math.ceil((active[0] + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(remaining),
      'X-RateLimit-Reset':     String(resetEpoch),
    });

    next();
  }

  // ── Public API ───────────────────────────────────────────────────────────────

  /** Stops the background cleanup timer (call during graceful shutdown). */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
